<script>
import {mapGetters} from "vuex"

export default {
  props: {
    timeElapsed: {
      type: String,
      default: '00:00'
    },
    timeDuration: {
      type: String,
      default: '00:00'
    },
    loadPercentage: {
      type: Number,
      default: 0
    }
  },
  data() {
    return {
      videoBlockLeft: 0,
      videoBlockWidth: 0,
      hoverWidth: 0,
      img: null,
      src: null
    }
  },
  computed: {
    ...mapGetters([
      'VIDEO',
      'IS_PLAY',
      'MUTED',
      'DURATION',
      'CURRENT_TIME'
    ])
  },
  methods: {
    nextVideo() {
      console.log('go to the next video')
    },
    muteVideo() {
      this.VIDEO.muted = !this.VIDEO.muted
      this.$store.commit('setMuted', !this.MUTED)
    },
    toggleFullScreen() {
      if (this.VIDEO.requestFullscreen) this.VIDEO.requestFullscreen()
    },
    width() {
      return (this.CURRENT_TIME / this.DURATION * 100) || 0
    },
    async pipVideo() {
      try {
          if (this.VIDEO !== document.pictureInPictureElement) {
          await this.VIDEO.requestPictureInPicture()
          } else {
          await document.exitPictureInPicture()
          }
      } catch (error) {
          console.error(error)
      }
    },
    showHover(e) {
      const skipTo = ((e.pageX - this.videoBlockLeft) * 100 / this.videoBlockWidth)
      this.hoverWidth = skipTo
      window.setTimeout(() => {
        this.$emit('capture', ((e.pageX - this.videoBlockLeft) / this.videoBlockWidth) * this.DURATION)
      }, 100)
    },
    hideHover() {
      this.hoverWidth = 0
    },
    skipToTime(e) {
      const skipTo = ((e.pageX - this.videoBlockLeft) / this.videoBlockWidth) * this.DURATION
      console.log(skipTo)
      this.VIDEO.currentTime = skipTo
      this.$store.commit('setCurrentTime', skipTo)
    },
    capture() {
      // let canvas = document.getElementById('canvas')
      // canvas.width = 200
      // canvas.height = 200
      // console.log(video)
      // canvas.getContext('2d').drawImage(video, 10, 0, video.videoWidth, video.videoHeight)
      // canvas.toBlob((blob) => {
      //   this.img = new Image()
      //   this.img.src = window.URL.createObjectURL(blob)
      //   this.src = this.img.src
      // })

    }
  },
  mounted() {
    this.videoBlockLeft = this.VIDEO.getBoundingClientRect().left + 10
    this.videoBlockWidth = this.VIDEO.getBoundingClientRect().width - 20
  }
}
</script>

<style scoped>
  .bottom {
    bottom: 0;
    left: 0;
    right: 0;
    width: 100%;
    position: absolute;
    padding: 0 10px 11px;
    box-sizing: border-box;
    background: linear-gradient(180deg, rgba(0, 0, 0, 0) 0%, rgba(0, 0, 0, 0.5) 100%, rgba(0, 0, 0, 0.5) 100%);
    background-blend-mode: multiply;
    border-radius: 5px;
  }
  .bottom__content {
    display: flex;
    justify-content: space-between;
    width: 100%;
    padding: 0 10px;
    box-sizing: border-box;
  }
  .bottom__left, .bottom__right {
    display: flex;
    align-items: center;
  }
  .bottom__right > div:not(:last-child), .bottom__left > div:not(:last-child) {
    margin-right: 16px;
  }
  .bottom__left > div, .bottom__right > div {
    cursor: pointer;
  }
  .bottom__timer {
    font-size: 14px;
    color: #EAEAEA;
  }
  .bottom__timer time:first-child {
    margin-right: 5px;
  }
  .bottom__timer time:first-child:after {
    content: '/';
    margin: 0 0 0 5px;
  }
  .progress-bar {
    width: 100%;
    height: 3.5px;
    margin-bottom: 10px;
    position: relative;
    padding: 5px 0;
    cursor: pointer;
  }
  .progress-bar__container {
    width: 100%;
    height: 100%;
    background: rgba(234, 234, 234, 0.2);
    position: relative;
  }
  .progress-bar__seek {
    position: absolute;
    background: linear-gradient(136.67deg, #FF409A 8.34%, #C438EF 95.26%);
    left: 0;
    top: 0;
    height: 100%;
    z-index: 3;
  }
  .progress-bar__seek:after {
    background: linear-gradient(136.67deg, #FF409A 8.34%, #C438EF 95.26%);
    width: 10px;
    height: 10px;
    border-radius: 50% 50%;
    content: '';
    position: absolute;
    top: -2px;
    right: -5px;
    opacity: 0;
  }
  .progress-bar:hover .progress-bar__seek {
    height: 5px;
    top: -1px;
  }
  .progress-bar:hover .progress-bar__seek:after {
    opacity: 1;
  }
  .progress-bar__load, .progress-bar__skip-to {
    position: absolute;
    left: 0;
    top: 0;
    height: 100%;
    background: rgba(234, 234, 234, 0.5);
    z-index: 1;
  }
  .progress-bar__skip-to {
    background: rgba(234, 234, 234, 0.7);
    z-index: 2;
    height: 5px;
    top: -1px;
  }
  .canvas {
    position: absolute;
    top: 100%;
    left: 0;
  }
</style>
